/* Enable 'font-optical-sizing' on your body or root element */
body {
  font-family: 'Merriweather Sans Variable', sans-serif; /* Example variable font */
  font-optical-sizing: auto;
  /* 'auto' tells the browser to apply optical sizing based on font-size */
}

/* No further CSS needed for individual elements; 
   the browser handles adjustments automatically based on their font-size */
h1 {
  font-size: 3rem;
}

p {
  font-size: 1rem;
}
